import socket
import struct
import math

# Game server settings
SERVER_IP = '127.0.0.1'
SERVER_PORT = 12345

class Player:
    def __init__(self, id, x, y):
        self.id = id
        self.x = x
        self.y = y

class GameServer:
    def __init__(self):
        self.players = []
        self.clients = []

    def add_player(self, player):
        self.players.append(player)

    def broadcast_game_state(self):
        game_state = {
            'players': self.players,
            'map_size': 1000
        }
        for client in self.clients:
            client.send(game_state)

    def handle_client_connection(self, client):
        self.clients.append(client)
        while True:
            data = client.recv(1024)
            if not data:
                break
            try:
                message_type, player_id, x, y = struct.unpack('BBff', data)
                for p in self.players:
                    distance = math.sqrt((x - p.x)**2 + (y - p.y)**2)
                    if distance < 100 and player_id != p.id:
                        client.send(struct.pack('Bf', message_type, distance))
            except struct.error:
                pass
        self.clients.remove(client)

    def start(self):
        server_socket = socket.socket(socket.AF_INET, socket.SOCK_STREAM)
        server_socket.bind((SERVER_IP, SERVER_PORT))
        server_socket.listen(5)
        print(f"Server listening on {SERVER_IP}:{SERVER_PORT}")

        while True:
            client_socket, address = server_socket.accept()
            self.handle_client_connection(client_socket)

if __name__ == "__main__":
    game_server = GameServer()
    game_server.add_player(Player(1, 500, 500))
    game_server.add_player(Player(2, 600, 600))

    game_server.start()